import ThemeToggle from './ThemeToggle';

function Navbar() {
  return (
    <nav className="navbar">
      <div className="logo">🐾 Meow Café</div>
      <div className="nav-links">
        <a href="#home">Home</a>
        <a href="#menu">Menu</a>
        <a href="#about">About</a>
      </div>
      <ThemeToggle />
    </nav>
  );
}

export default Navbar;
